interface ClientIdentity {
  provider: string;
  source: string;
}

/**
 * 根据 MCP clientInfo.name 推断 provider 和 source。
 * clientInfo 在 MCP initialize 握手阶段由客户端主动上报。
 */
function inferClientIdentity(clientName: string): ClientIdentity {
  const name = clientName.toLowerCase();

  if (name.includes("opencode")) {
    return { provider: "anthropic", source: "opencode" };
  }
  if (name.includes("cline") || name.includes("roo")) {
    return { provider: "anthropic", source: "cline" };
  }
  if (name.includes("cursor")) {
    return { provider: "anthropic", source: "cursor" };
  }
  if (name.includes("claude")) {
    return { provider: "anthropic", source: "claude-code" };
  }
  if (name.includes("copilot") || name.includes("vscode")) {
    return { provider: "openai", source: "copilot" };
  }
  if (name.includes("continue")) {
    return { provider: "unknown", source: "continue" };
  }

  return { provider: "unknown", source: "mcp-tool-call" };
}

