              model: {
                type: "string",
                description:
                  "当前 Agent 使用的模型名称（如 claude-sonnet-4-5）。调用时应传入实际使用的模型 ID。",
              },
              provider: {
                type: "string",
                description:
                  "模型提供商（如 anthropic、openai、deepseek、ollama 等）。调用时应传入实际的提供商标识。",
              },
              source: {
                type: "string",
                description:
                  "发起调用的 Agent 工具名称（如 opencode、cline、cursor、claude-code 等）。调用时应传入实际的工具名称。",
