  process.stderr.write(`[agentlog-mcp] 客户端：${clientName || "(未知)"} → provider=${clientIdentity.provider} source=${clientIdentity.source}\n`);

  // ── 优雅退出 ────────────────────────────────

  process.on("SIGINT", async () => {
    await server.close();
    process.exit(0);
  });

  process.on("SIGTERM", async () => {
    await server.close();
    process.exit(0);
  });
}

